ALTER TABLE "IndustrialKnowledgeGraphEdge" ADD CONSTRAINT "IndustrialKnowledgeGraphEdge_targetNodeId_fkey" FOREIGN KEY ("targetNodeId") REFERENCES "IndustrialKnowledgeGraphNode"("id") ON DELETE CASCADE ON UPDATE CASCADE;

ALTER TABLE "KnowledgeGraphSnapshot" ADD CONSTRAINT "KnowledgeGraphSnapshot_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE;

